-- Baseline schema for a fresh SGP database.
-- Existing non-empty databases can still be baselined by Flyway before V2.

create table academic_cycles (active bit not null, deleted bit not null, order_number integer, career_id bigint, created_at datetime(6), deleted_at datetime(6), id bigint not null auto_increment, updated_at datetime(6), name varchar(255) not null, primary key (id)) engine=InnoDB;
create table account_roles (account_id bigint not null, role_id bigint not null, primary key (account_id, role_id)) engine=InnoDB;
create table accounts (deleted bit not null, enabled bit not null, locked bit not null, password_change_required bit not null, academic_cycle_id bigint, created_at datetime(6), deleted_at datetime(6), id bigint not null auto_increment, institution_id bigint, person_id bigint, updated_at datetime(6), password varchar(255) not null, profile_image_type varchar(255), username varchar(255) not null, profile_image LONGBLOB, primary key (id)) engine=InnoDB;
create table activity_evaluation_aspects (evaluation_id bigint not null, id bigint not null auto_increment, item varchar(1000), aspect_type enum ('ESPECIFICO','GENERAL'), level enum ('ALTO','BAJO','MEDIO'), primary key (id)) engine=InnoDB;
create table activity_evaluations (activities_completion_percentage decimal(5,2), deleted bit not null, evaluation_date date, hours_completed integer, course_id bigint not null, created_at datetime(6), deleted_at datetime(6), educational_institution_id bigint not null, enrollment_id bigint not null, evaluated_by bigint not null, id bigint not null auto_increment, student_id bigint not null, updated_at datetime(6), academic_period varchar(255), educational_institution_address varchar(255), educational_institution_code varchar(255), educational_institution_email varchar(255), educational_institution_name varchar(255), educational_institution_phone varchar(255), student_email varchar(255), student_full_name varchar(255), student_identification varchar(255), student_phone varchar(255), development_mode enum ('ONLINE','PRESENCIAL'), practice_type enum ('DOCENTE','ELABORACION','OBSERVACION'), primary key (id)) engine=InnoDB;
create table activity_plan_activity_weeks (end_date date, start_date date, week_number integer, id bigint not null auto_increment, plan_id bigint not null, activities LONGTEXT, primary key (id)) engine=InnoDB;
create table activity_plan_schedule_weeks (end_date date, start_date date, week_number integer, id bigint not null auto_increment, plan_id bigint not null, scheduled_activities LONGTEXT, primary key (id)) engine=InnoDB;
create table activity_plans (deleted bit not null, director_approved bit not null, practice_tutor_approved bit not null, review_cycle integer, student_count integer, teacher_count integer, approved_at datetime(6), course_id bigint not null, created_at datetime(6), deleted_at datetime(6), director_reviewed_at datetime(6), director_reviewed_by bigint, educational_institution_id bigint not null, enrollment_id bigint not null, id bigint not null auto_increment, reviewed_at datetime(6), reviewed_by bigint, student_id bigint not null, submitted_at datetime(6), updated_at datetime(6), curricular_organization_unit varchar(255), educational_institution_address varchar(255), educational_institution_code varchar(255), educational_institution_email varchar(255), educational_institution_name varchar(255), educational_institution_phone varchar(255), integrative_knowledge_project varchar(255), practice_type varchar(255), student_email varchar(255), student_full_name varchar(255), student_identification varchar(255), student_phone varchar(255), subject_denomination varchar(255), activities_feedback LONGTEXT, approval_feedback LONGTEXT, general_info_feedback LONGTEXT, general_objective LONGTEXT, human_resources LONGTEXT, institutional_values LONGTEXT, legal_resources LONGTEXT, mission LONGTEXT, objectives_feedback LONGTEXT, physical_resources LONGTEXT, presentation LONGTEXT, presentation_feedback LONGTEXT, resources_feedback LONGTEXT, schedule_feedback LONGTEXT, specific_objective1 LONGTEXT, specific_objective2 LONGTEXT, specific_objective3 LONGTEXT, status enum ('APPROVED','DRAFT','NEEDS_CORRECTION','SUBMITTED'), technological_resources LONGTEXT, vision LONGTEXT, primary key (id)) engine=InnoDB;
create table cantons (id bigint not null auto_increment, province_id bigint, code varchar(255) not null, name varchar(255) not null, primary key (id)) engine=InnoDB;
create table careers (active bit not null, deleted bit not null, duration_cycles integer, created_at datetime(6), deleted_at datetime(6), faculty_id bigint, id bigint not null auto_increment, updated_at datetime(6), code varchar(255) not null, description varchar(255), name varchar(255) not null, primary key (id)) engine=InnoDB;
create table completed_activity_record_entries (activity_date date, end_time time(0), start_time time(0), total_minutes integer, id bigint not null auto_increment, record_id bigint not null, evidence_link varchar(2000), developed_activities LONGTEXT, feedback LONGTEXT, suggestions LONGTEXT, primary key (id)) engine=InnoDB;
create table completed_activity_records (deleted bit not null, delivery_date date, director_approved bit not null, practice_tutor_approved bit not null, review_cycle integer, total_minutes integer, approved_at datetime(6), course_id bigint not null, created_at datetime(6), deleted_at datetime(6), director_reviewed_at datetime(6), director_reviewed_by bigint, educational_institution_id bigint not null, enrollment_id bigint not null, id bigint not null auto_increment, reviewed_at datetime(6), reviewed_by bigint, student_id bigint not null, submitted_at datetime(6), updated_at datetime(6), academic_period varchar(255), educational_institution_address varchar(255), educational_institution_code varchar(255), educational_institution_email varchar(255), educational_institution_name varchar(255), educational_institution_phone varchar(255), student_email varchar(255), student_full_name varchar(255), student_identification varchar(255), student_phone varchar(255), accreditation_feedback LONGTEXT, activities_feedback LONGTEXT, development_mode enum ('ONLINE','PRESENCIAL'), general_info_feedback LONGTEXT, practice_type enum ('DOCENTE','ELABORACION','OBSERVACION'), status enum ('APPROVED','DRAFT','NEEDS_CORRECTION','SUBMITTED'), primary key (id)) engine=InnoDB;
create table course_groups (active bit not null, capacity integer, deleted bit not null, course_id bigint not null, created_at datetime(6), created_by bigint, deleted_at datetime(6), id bigint not null auto_increment, institutional_tutor_id bigint, updated_at datetime(6), description varchar(3000), name varchar(255) not null, primary key (id)) engine=InnoDB;
create table courses (active bit not null, capacity integer, deleted bit not null, locked bit not null, created_at datetime(6), created_by bigint, deleted_at datetime(6), end_date datetime(6), id bigint not null auto_increment, institutional_tutor_id bigint, practice_tutor_id bigint, start_date datetime(6), subject_id bigint, updated_at datetime(6), description varchar(3000), code varchar(255), curricular_organization_unit varchar(255), integrative_knowledge_project varchar(255), name varchar(255) not null, practice_type varchar(255), general_objective LONGTEXT, specific_objective1 LONGTEXT, specific_objective2 LONGTEXT, specific_objective3 LONGTEXT, primary key (id)) engine=InnoDB;
create table enrollments (account_id bigint, course_group_id bigint, course_id bigint, enrolled_at datetime(6), id bigint not null auto_increment, status enum ('APPROVED','COMPLETED','PENDING','REJECTED'), primary key (id)) engine=InnoDB;
create table faculties (active bit not null, deleted bit not null, created_at datetime(6), deleted_at datetime(6), id bigint not null auto_increment, institution_id bigint, updated_at datetime(6), code varchar(255) not null, description varchar(255), name varchar(255) not null, primary key (id)) engine=InnoDB;
create table feedback_comments (review_cycle integer not null, author_id bigint, created_at datetime(6), document_id bigint not null, entry_id bigint not null, id bigint not null auto_increment, updated_at datetime(6), author_role varchar(120), section_key varchar(120) not null, document_type enum ('ACTIVITY_PLAN','COMPLETED_ACTIVITY_RECORD','FINAL_REPORT','PRACTICE_REPORT') not null, message LONGTEXT, primary key (id)) engine=InnoDB;
create table feedback_history_entries (review_cycle integer not null, author_id bigint, created_at datetime(6), document_id bigint not null, entry_id bigint not null, id bigint not null auto_increment, updated_at datetime(6), author_role varchar(120), section_key varchar(120) not null, document_type enum ('ACTIVITY_PLAN','COMPLETED_ACTIVITY_RECORD','FINAL_REPORT','PRACTICE_REPORT') not null, message LONGTEXT, primary key (id)) engine=InnoDB;
create table final_report_activity_weeks (end_date date, start_date date, week_number integer, id bigint not null auto_increment, report_id bigint not null, activities LONGTEXT, primary key (id)) engine=InnoDB;
create table final_reports (deleted bit not null, director_approved bit not null, institutional_tutor_approved bit not null, practice_tutor_approved bit not null, review_cycle integer, approved_at datetime(6), course_id bigint not null, created_at datetime(6), deleted_at datetime(6), director_reviewed_at datetime(6), director_reviewed_by bigint, educational_institution_id bigint not null, enrollment_id bigint not null, id bigint not null auto_increment, institutional_reviewed_at datetime(6), institutional_reviewed_by bigint, practice_reviewed_at datetime(6), practice_reviewed_by bigint, student_id bigint not null, submitted_at datetime(6), updated_at datetime(6), educational_institution_address varchar(255), educational_institution_code varchar(255), educational_institution_email varchar(255), educational_institution_name varchar(255), educational_institution_phone varchar(255), student_email varchar(255), student_full_name varchar(255), student_identification varchar(255), student_phone varchar(255), antecedents LONGTEXT, conclusion1 LONGTEXT, conclusion2 LONGTEXT, conclusion3 LONGTEXT, director_activities_feedback LONGTEXT, director_antecedents_feedback LONGTEXT, director_approval_feedback LONGTEXT, director_conclusions_feedback LONGTEXT, director_general_info_feedback LONGTEXT, director_objective_feedback LONGTEXT, director_recommendations_feedback LONGTEXT, institutional_activities_feedback LONGTEXT, institutional_antecedents_feedback LONGTEXT, institutional_approval_feedback LONGTEXT, institutional_conclusions_feedback LONGTEXT, institutional_general_info_feedback LONGTEXT, institutional_objective_feedback LONGTEXT, institutional_recommendations_feedback LONGTEXT, objective LONGTEXT, practice_activities_feedback LONGTEXT, practice_antecedents_feedback LONGTEXT, practice_approval_feedback LONGTEXT, practice_conclusions_feedback LONGTEXT, practice_general_info_feedback LONGTEXT, practice_objective_feedback LONGTEXT, practice_recommendations_feedback LONGTEXT, recommendation1 LONGTEXT, recommendation2 LONGTEXT, recommendation3 LONGTEXT, status enum ('APPROVED','DRAFT','NEEDS_CORRECTION','SUBMITTED'), primary key (id)) engine=InnoDB;
create table grades (active bit not null, deleted bit not null, level integer, created_at datetime(6), deleted_at datetime(6), id bigint not null auto_increment, institution_id bigint, updated_at datetime(6), code varchar(255), name varchar(255) not null, primary key (id)) engine=InnoDB;
create table institution_education_levels (institution_id bigint not null, education_level enum ('BGU','EGB','EI')) engine=InnoDB;
create table institutions (accepts_interns bit not null, active bit not null, agreement_active bit not null, deleted bit not null, student_count integer, teacher_count integer, canton_id bigint, created_at datetime(6), deleted_at datetime(6), id bigint not null auto_increment, parish_id bigint, province_id bigint, updated_at datetime(6), address varchar(255), code varchar(255) not null, email varchar(255), name varchar(255) not null, phone varchar(255), website varchar(255), institutional_values LONGTEXT, mission LONGTEXT, modality enum ('DISTANCIA','PRESENCIAL','SEMIPRESENCIAL','VIRTUAL'), regime enum ('COSTA','SIERRA'), support enum ('FISCOMISIONAL','MUNICIPAL','PRIVADO','PUBLICO'), type enum ('COLEGIO','EMPRESA','ESCUELA','FUNDACION','INSTITUTO','UNIVERSIDAD'), vision LONGTEXT, primary key (id)) engine=InnoDB;
create table notifications (is_read bit, created_at datetime(6), id bigint not null auto_increment, recipient_id bigint not null, updated_at datetime(6), link varchar(255), title varchar(255), type varchar(255), message LONGTEXT, primary key (id)) engine=InnoDB;
create table parishes (canton_id bigint, id bigint not null auto_increment, code varchar(255) not null, name varchar(255) not null, primary key (id)) engine=InnoDB;
