create table practice_follow_up_sessions (end_time time(0), start_time time(0), supervision_date date, total_minutes integer, id bigint not null auto_increment, report_id bigint not null, supervised_activities LONGTEXT, primary key (id)) engine=InnoDB;
create table practice_photos (deleted bit not null, practice_date date, course_id bigint not null, created_at datetime(6), deleted_at datetime(6), enrollment_id bigint not null, file_size bigint not null, id bigint not null auto_increment, student_id bigint not null, updated_at datetime(6), uploaded_at datetime(6), uploaded_by bigint not null, content_type varchar(255) not null, original_filename varchar(255) not null, data LONGBLOB not null, description LONGTEXT, primary key (id)) engine=InnoDB;
create table practice_report_activity_weeks (end_date date, start_date date, week_number integer, id bigint not null auto_increment, report_id bigint not null, activities LONGTEXT, primary key (id)) engine=InnoDB;
create table practice_reports (deleted bit not null, director_approved bit not null, practice_tutor_approved bit not null, review_cycle integer, approved_at datetime(6), course_id bigint not null, created_at datetime(6), deleted_at datetime(6), director_reviewed_at datetime(6), director_reviewed_by bigint, educational_institution_id bigint not null, enrollment_id bigint not null, id bigint not null auto_increment, reviewed_at datetime(6), reviewed_by bigint, student_id bigint not null, submitted_at datetime(6), updated_at datetime(6), educational_institution_address varchar(255), educational_institution_code varchar(255), educational_institution_email varchar(255), educational_institution_name varchar(255), educational_institution_phone varchar(255), student_email varchar(255), student_full_name varchar(255), student_identification varchar(255), student_phone varchar(255), activities_feedback LONGTEXT, approval_feedback LONGTEXT, conclusion1 LONGTEXT, conclusion2 LONGTEXT, conclusion3 LONGTEXT, conclusions_feedback LONGTEXT, general_info_feedback LONGTEXT, general_objective LONGTEXT, methodology LONGTEXT, methodology_feedback LONGTEXT, objectives_feedback LONGTEXT, presentation LONGTEXT, presentation_feedback LONGTEXT, recommendation1 LONGTEXT, recommendation2 LONGTEXT, recommendation3 LONGTEXT, recommendations_feedback LONGTEXT, specific_objective1 LONGTEXT, specific_objective2 LONGTEXT, specific_objective3 LONGTEXT, status enum ('APPROVED','DRAFT','NEEDS_CORRECTION','SUBMITTED'), primary key (id)) engine=InnoDB;
